import{_ as e,o as i,c as l,ak as r}from"./chunks/framework.oFDsBAuP.js";const c=JSON.parse('{"title":"功能指南概述","description":"","frontmatter":{"title":"功能指南概述","source":"https://docs.newapi.pro/zh/docs/guide/feature-guide","syncedAt":"2026-05-10T11:19:57.626Z"},"headers":[],"relativePath":"settings/index.md","filePath":"settings/index.md"}'),t={name:"settings/index.md"};function o(h,a,p,n,d,u){return i(),l("div",null,[...a[0]||(a[0]=[r('<h2 id="功能指南概述" tabindex="-1">功能指南概述 <a class="header-anchor" href="#功能指南概述" aria-label="Permalink to &quot;功能指南概述&quot;">​</a></h2><p>New API 功能指南，按角色分为用户指南与管理员指南两部分</p><p>New API 是一个统一的 LLM 网关平台，将多个 AI 服务商的接口聚合为标准的 OpenAI 兼容 API，让你通过一个地址访问数十种模型。本指南按角色分为用户指南与管理员指南两部分。</p><p><img src="https://docs.newapi.pro/_next/image?url=%2F_next%2Fstatic%2Fmedia%2Fhome.b33db84d.png&amp;w=3840&amp;q=75&amp;dpl=dpl_5xWUpQnJ3GSwAKGo6u8mmg9BRqma" alt="系统首页"></p><p>根据账号权限，平台分为三种角色，各自拥有不同的功能范围。</p><h3 id="普通用户" tabindex="-1"><a href="#普通用户">普通用户</a> <a class="header-anchor" href="#普通用户" aria-label="Permalink to &quot;[普通用户](#普通用户)&quot;">​</a></h3><p>注册后的默认角色，可以创建令牌、调用 API、查看个人用量、充值与订阅。</p><h3 id="管理员-admin" tabindex="-1"><a href="#管理员admin">管理员（Admin）</a> <a class="header-anchor" href="#管理员-admin" aria-label="Permalink to &quot;[管理员（Admin）](#管理员admin)&quot;">​</a></h3><p>由 Root 提升的管理角色，在用户权限基础上，可以管理渠道、用户、兑换码、日志、模型与分组。</p><h3 id="超级管理员-root" tabindex="-1"><a href="#超级管理员root">超级管理员（Root）</a> <a class="header-anchor" href="#超级管理员-root" aria-label="Permalink to &quot;[超级管理员（Root）](#超级管理员root)&quot;">​</a></h3><p>最高权限角色，在管理员基础上，额外拥有系统全局设置、自定义 OAuth、性能监控等能力。</p><p>适用于所有已登录用户，涵盖从注册到日常使用的完整流程。</p><h3 id="注册与登录" tabindex="-1"><a href="#注册与登录">注册与登录</a> <a class="header-anchor" href="#注册与登录" aria-label="Permalink to &quot;[注册与登录](#注册与登录)&quot;">​</a></h3><p>支持账号密码及 GitHub、Discord 等多种第三方 OAuth 登录方式。</p><ul><li>账号密码登录</li><li>第三方 OAuth 登录</li><li>忘记密码重置</li><li>新用户注册流程</li></ul><p><a href="./user/auth.html">查看详细文档 →</a></p><h3 id="个人设置" tabindex="-1"><a href="#个人设置">个人设置</a> <a class="header-anchor" href="#个人设置" aria-label="Permalink to &quot;[个人设置](#个人设置)&quot;">​</a></h3><p>管理账号信息、开启 2FA 双因素认证、绑定 Passkey 无密码登录。</p><ul><li>修改用户名和密码</li><li>绑定邮箱地址</li><li>开启双因素认证（2FA）</li><li>注册 Passkey 无密码登录</li><li>绑定第三方账号</li></ul><p><a href="./user/personal-setting.html">查看详细文档 →</a></p><h3 id="令牌管理" tabindex="-1"><a href="#令牌管理">令牌管理</a> <a class="header-anchor" href="#令牌管理" aria-label="Permalink to &quot;[令牌管理](#令牌管理)&quot;">​</a></h3><p>创建和管理 API 调用凭证，支持配额限制、模型限制、IP 白名单。</p><ul><li>创建新令牌</li><li>配置令牌权限</li><li>设置配额限制</li><li>配置模型限制</li><li>设置 IP 白名单</li></ul><p><a href="./user/token.html">查看详细文档 →</a></p><h3 id="使用记录" tabindex="-1"><a href="#使用记录">使用记录</a> <a class="header-anchor" href="#使用记录" aria-label="Permalink to &quot;[使用记录](#使用记录)&quot;">​</a></h3><p>查看每次 API 调用的模型、Token 消耗、配额扣减等详细记录。</p><ul><li>查看调用日志</li><li>搜索与过滤记录</li><li>数据统计图表</li><li>配额消耗分析</li></ul><p><a href="./user/log.html">查看详细文档 →</a></p><h3 id="钱包管理" tabindex="-1"><a href="#钱包管理">钱包管理</a> <a class="header-anchor" href="#钱包管理" aria-label="Permalink to &quot;[钱包管理](#钱包管理)&quot;">​</a></h3><p>支持在线支付（如支付宝、Stripe）、兑换码充值，以及邀请奖励与账单查看。</p><ul><li>在线支付充值</li><li>兑换码充值</li><li>邀请奖励</li><li>查看充值记录</li></ul><p><a href="./user/topup.html">查看详细文档 →</a></p><h3 id="订阅计划" tabindex="-1"><a href="#订阅计划">订阅计划</a> <a class="header-anchor" href="#订阅计划" aria-label="Permalink to &quot;[订阅计划](#订阅计划)&quot;">​</a></h3><p>按周期购买的套餐，适合有稳定用量需求的用户。</p><ul><li>查看订阅套餐</li><li>购买订阅</li><li>管理自动续费</li></ul><p><a href="https://docs.newapi.pro/zh/docs/guide/feature-guide/user/subscription" target="_blank" rel="noreferrer">查看详细文档 →</a></p><h3 id="模型广场" tabindex="-1"><a href="#模型广场">模型广场</a> <a class="header-anchor" href="#模型广场" aria-label="Permalink to &quot;[模型广场](#模型广场)&quot;">​</a></h3><p>浏览可用模型、筛选供应商与计费类型，并查看价格说明。</p><ul><li>查看模型价格</li><li>搜索特定模型</li><li>了解计费规则</li></ul><p><a href="./user/pricing.html">查看详细文档 →</a></p><h3 id="任务" tabindex="-1"><a href="#任务">任务</a> <a class="header-anchor" href="#任务" aria-label="Permalink to &quot;[任务](#任务)&quot;">​</a></h3><p>查看和管理异步生成任务的状态和结果。</p><ul><li>查看任务列表</li><li>查看任务详情</li><li>管理任务进度</li></ul><p><a href="./user/task.html">查看详细文档 →</a></p><p>适用于 Admin 及 Root 角色，涵盖平台运营与系统配置的全部功能。</p><h3 id="渠道管理" tabindex="-1"><a href="#渠道管理">渠道管理</a> <a class="header-anchor" href="#渠道管理" aria-label="Permalink to &quot;[渠道管理](#渠道管理)&quot;">​</a></h3><p>配置 AI 服务商渠道，支持多 Key 轮询、优先级、自动禁用等策略。</p><ul><li>添加新渠道</li><li>配置渠道参数</li><li>渠道测试</li><li>批量操作</li><li>多 Key 模式配置</li></ul><p><a href="https://docs.newapi.pro/zh/docs/guide/feature-guide/admin/channel" target="_blank" rel="noreferrer">查看详细文档 →</a></p><h3 id="用户管理" tabindex="-1"><a href="#用户管理">用户管理</a> <a class="header-anchor" href="#用户管理" aria-label="Permalink to &quot;[用户管理](#用户管理)&quot;">​</a></h3><p>查看和管理所有用户，修改角色、分组、配额，启用或禁用账号。</p><ul><li>查看用户列表</li><li>编辑用户信息</li><li>修改用户角色</li><li>调整用户配额</li><li>搜索用户</li></ul><p><a href="https://docs.newapi.pro/zh/docs/guide/feature-guide/admin/user" target="_blank" rel="noreferrer">查看详细文档 →</a></p><h3 id="兑换码管理" tabindex="-1"><a href="#兑换码管理">兑换码管理</a> <a class="header-anchor" href="#兑换码管理" aria-label="Permalink to &quot;[兑换码管理](#兑换码管理)&quot;">​</a></h3><p>批量生成和管理配额兑换码。</p><ul><li>批量生成兑换码</li><li>设置兑换码面值</li><li>导出兑换码</li><li>查看使用状态</li></ul><p><a href="https://docs.newapi.pro/zh/docs/guide/feature-guide/admin/redemption" target="_blank" rel="noreferrer">查看详细文档 →</a></p><h3 id="日志管理" tabindex="-1"><a href="#日志管理">日志管理</a> <a class="header-anchor" href="#日志管理" aria-label="Permalink to &quot;[日志管理](#日志管理)&quot;">​</a></h3><p>查看全站 API 调用日志和用户操作记录。</p><ul><li>查看全站日志</li><li>高级筛选</li><li>数据统计分析</li></ul><p><a href="https://docs.newapi.pro/zh/docs/guide/feature-guide/admin/log" target="_blank" rel="noreferrer">查看详细文档 →</a></p><h3 id="订阅管理" tabindex="-1"><a href="#订阅管理">订阅管理</a> <a class="header-anchor" href="#订阅管理" aria-label="Permalink to &quot;[订阅管理](#订阅管理)&quot;">​</a></h3><p>创建和管理订阅套餐。</p><ul><li>创建订阅套餐</li><li>编辑套餐信息</li><li>管理订阅用户</li></ul><p><a href="https://docs.newapi.pro/zh/docs/guide/feature-guide/admin/subscription" target="_blank" rel="noreferrer">查看详细文档 →</a></p><h3 id="模型管理" tabindex="-1"><a href="#模型管理">模型管理</a> <a class="header-anchor" href="#模型管理" aria-label="Permalink to &quot;[模型管理](#模型管理)&quot;">​</a></h3><p>配置模型定价和可用性。</p><ul><li>设置模型倍率</li><li>启用或禁用模型</li><li>批量修改定价</li></ul><p><a href="https://docs.newapi.pro/zh/docs/guide/feature-guide/admin/model" target="_blank" rel="noreferrer">查看详细文档 →</a></p><h3 id="分组管理" tabindex="-1"><a href="#分组管理">分组管理</a> <a class="header-anchor" href="#分组管理" aria-label="Permalink to &quot;[分组管理](#分组管理)&quot;">​</a></h3><p>创建用户分组，实现差异化计费和渠道分配。</p><ul><li>创建用户分组</li><li>配置分组倍率</li><li>分配渠道</li></ul><p><a href="https://docs.newapi.pro/zh/docs/guide/feature-guide/admin/group" target="_blank" rel="noreferrer">查看详细文档 →</a></p><h3 id="系统设置-root-专属" tabindex="-1"><a href="#系统设置root-专属">系统设置（Root 专属）</a> <a class="header-anchor" href="#系统设置-root-专属" aria-label="Permalink to &quot;[系统设置（Root 专属）](#系统设置root-专属)&quot;">​</a></h3><p>Root 专属全局配置中心，涵盖站点信息、计费规则、支付、OAuth 等参数。</p><ul><li>站点基本信息</li><li>计费规则配置</li><li>支付方式配置</li><li>邮件服务配置</li><li>注册与登录设置</li></ul><p><a href="https://docs.newapi.pro/zh/docs/guide/feature-guide/admin/system-setting" target="_blank" rel="noreferrer">查看详细文档 →</a></p><h3 id="系统高级配置-root-专属" tabindex="-1"><a href="#系统高级配置root-专属">系统高级配置（Root 专属）</a> <a class="header-anchor" href="#系统高级配置-root-专属" aria-label="Permalink to &quot;[系统高级配置（Root 专属）](#系统高级配置root-专属)&quot;">​</a></h3><p>系统设置的详细配置选项，包含支付、限流、聊天、绘图等高级功能。</p><ul><li>支付设置（EPay、Stripe）</li><li>限流设置</li><li>倍率设置</li><li>聊天设置</li><li>绘图设置</li><li>数据看板设置</li><li>模型设置</li><li>运营设置</li></ul><p><a href="https://docs.newapi.pro/zh/docs/guide/feature-guide/admin/system-setting-advanced" target="_blank" rel="noreferrer">查看详细文档 →</a></p><h3 id="自定义-oauth-root-专属" tabindex="-1"><a href="#自定义-oauthroot-专属">自定义 OAuth（Root 专属）</a> <a class="header-anchor" href="#自定义-oauth-root-专属" aria-label="Permalink to &quot;[自定义 OAuth（Root 专属）](#自定义-oauthroot-专属)&quot;">​</a></h3><p>配置自定义 OAuth 登录提供商。</p><ul><li>添加 OAuth 提供商</li><li>配置 OAuth 参数</li><li>测试 OAuth 登录</li></ul><p><a href="https://docs.newapi.pro/zh/docs/guide/feature-guide/admin/custom-oauth" target="_blank" rel="noreferrer">查看详细文档 →</a></p><h3 id="性能监控-root-专属" tabindex="-1"><a href="#性能监控root-专属">性能监控（Root 专属）</a> <a class="header-anchor" href="#性能监控-root-专属" aria-label="Permalink to &quot;[性能监控（Root 专属）](#性能监控root-专属)&quot;">​</a></h3><p>查看系统性能指标和运行状态。</p><ul><li>查看系统负载</li><li>监控渠道性能</li><li>分析响应时间</li></ul><p><a href="https://docs.newapi.pro/zh/docs/guide/feature-guide/admin/performance" target="_blank" rel="noreferrer">查看详细文档 →</a></p><h3 id="文档配置-root-专属" tabindex="-1"><a href="#文档配置root-专属">文档配置（Root 专属）</a> <a class="header-anchor" href="#文档配置-root-专属" aria-label="Permalink to &quot;[文档配置（Root 专属）](#文档配置root-专属)&quot;">​</a></h3><p>配置文档站点的显示内容。</p><ul><li>自定义文档内容</li><li>配置文档链接</li></ul><p><a href="https://docs.newapi.pro/zh/docs/guide/feature-guide/admin/docs-config" target="_blank" rel="noreferrer">查看详细文档 →</a></p><p>这篇文档对您有帮助吗？</p><p>最后更新于</p><hr><blockquote><p><strong>来源</strong>：<a href="https://docs.newapi.pro/zh/docs/guide/feature-guide" target="_blank" rel="noreferrer">官方文档</a>（New API）。本站为离线整理副本，如有出入以官方为准。</p></blockquote>',97)])])}const f=e(t,[["render",o]]);export{c as __pageData,f as default};
